/* ─── REVEAL HOOK ────────────────────────────────────────────────────────── */
function useRev(cls = 'reveal') {
  const r = useRef();
  useEffect(() => {
    const el = r.current; if (!el) return;
    const obs = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) el.querySelectorAll(`.${cls}`).forEach(x => x.classList.add('v')); });
    }, { threshold: 0.08 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [cls]);
  return r;
}

/* ─── CURSOR SYSTEM ──────────────────────────────────────────────────────── */
const CursorSystem = () => {
  const cx = useRef(-200), cy = useRef(-200);
  const dotRef = useRef(null);
  const ringRef = useRef(null);
  const [paws, setPaws] = useState([]);
  const lastPawPos = useRef({ x: -999, y: -999 });
  const lastPawTime = useRef(0);

  useEffect(() => {
    let raf;
    const rx = { v: -200 }, ry = { v: -200 };

    const onMove = (e) => {
      cx.current = e.clientX; cy.current = e.clientY;
      const now = Date.now();
      const dx = e.clientX - lastPawPos.current.x;
      const dy = e.clientY - lastPawPos.current.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 60 && now - lastPawTime.current > 260) {
        lastPawTime.current = now;
        lastPawPos.current = { x: e.clientX, y: e.clientY };
        const id = now + Math.random();
        const size = 13 + Math.random() * 12;
        const rot = -35 + Math.random() * 70;
        setPaws(p => [...p.slice(-10), { id, x: e.clientX, y: e.clientY, size, rot }]);
        setTimeout(() => setPaws(p => p.filter(pw => pw.id !== id)), 1600);
      }
    };

    const tick = () => {
      rx.v += (cx.current - rx.v) * 0.14;
      ry.v += (cy.current - ry.v) * 0.14;
      if (dotRef.current) {
        dotRef.current.style.transform = `translate(${cx.current - 5}px,${cy.current - 5}px)`;
      }
      if (ringRef.current) {
        ringRef.current.style.transform = `translate(${rx.v - 14}px,${ry.v - 14}px)`;
      }
      raf = requestAnimationFrame(tick);
    };

    window.addEventListener('mousemove', onMove, { passive: true });
    raf = requestAnimationFrame(tick);
    return () => { window.removeEventListener('mousemove', onMove); cancelAnimationFrame(raf); };
  }, []);

  return (
    <>
      {/* Dot */}
      <div ref={dotRef} style={{ position:'fixed', top:0, left:0, width:10, height:10, borderRadius:'50%', background:C.crimson, pointerEvents:'none', zIndex:99999, willChange:'transform' }} />
      {/* Ring */}
      <div ref={ringRef} style={{ position:'fixed', top:0, left:0, width:28, height:28, borderRadius:'50%', border:`1.5px solid rgba(178,34,34,0.55)`, pointerEvents:'none', zIndex:99998, willChange:'transform', transition:'width .15s,height .15s' }} />
      {/* Paws */}
      <div style={{ position:'fixed', inset:0, pointerEvents:'none', zIndex:99997, overflow:'hidden' }}>
        {paws.map(p => (
          <div key={p.id} style={{ position:'fixed', left:p.x - p.size/2, top:p.y - p.size/2, '--pr':`${p.rot}deg`, animation:'pawFade 1.6s ease forwards', pointerEvents:'none' }}>
            <PawSVG size={p.size} color={C.crimson} opacity={0.5} />
          </div>
        ))}
      </div>
    </>
  );
};

/* ─── PAW SVG ────────────────────────────────────────────────────────────── */
