/* ─── INK SPLAT SYSTEM (hits surface and blooms) ─────────────────────────── */
const InkSplats = () => {
  const [splats, setSplats] = useState([]);
  useEffect(() => {
    const spawn = () => {
      const id = Date.now() + Math.random();
      const x = 5 + Math.random() * 90;
      const y = 10 + Math.random() * 85;
      const size = 18 + Math.random() * 28;
      const sr = -30 + Math.random() * 60;
      const colors = [C.crimson, C.dark, '#8B1010', C.gold];
      const color = colors[Math.floor(Math.random() * colors.length)];
      setSplats(p => [...p.slice(-8), { id, x, y, size, sr, color }]);
      setTimeout(() => setSplats(p => p.filter(s => s.id !== id)), 2200);
    };
    const iv = setInterval(spawn, 2800 + Math.random() * 2000);
    return () => clearInterval(iv);
  }, []);

  return (
    <div style={{ position:'fixed', inset:0, pointerEvents:'none', zIndex:2, overflow:'hidden' }}>
      {splats.map(s => (
        <div key={s.id} style={{ position:'fixed', left:`${s.x}%`, top:`${s.y}%`, transform:'translate(-50%,-50%)' }}>
          {/* Main splat blob */}
          <div style={{ '--sr':`${s.sr}deg`, width:s.size, height:s.size * 0.7, borderRadius:'50%', background:`radial-gradient(ellipse, ${s.color}cc 0%, ${s.color}44 55%, transparent 100%)`, animation:'splatSpread 2s ease forwards', position:'absolute', top:0, left:0 }} />
          {/* Small drop impact */}
          <div style={{ width:s.size*0.35, height:s.size*0.35, borderRadius:'50%', background:`${s.color}bb`, animation:'splatDrop 2s ease forwards', position:'absolute', top:'25%', left:'30%' }} />
          {/* Splatter arms */}
          {Array.from({length:5}).map((_,i) => {
            const ang = (i/5)*360;
            const len = s.size*0.4 + Math.random()*s.size*0.3;
            return (
              <div key={i} style={{ position:'absolute', top:'50%', left:'50%', width:len, height:2 + Math.random()*2, background:`linear-gradient(to right, ${s.color}99, transparent)`, transformOrigin:'0 50%', transform:`rotate(${ang}deg)`, opacity:0, animation:`splatSpread 2s ease ${i*0.05}s forwards` }} />
            );
          })}
        </div>
      ))}
    </div>
  );
};

/* ─── TAIL INDICATOR ─────────────────────────────────────────────────────── */
const TailIndicator = ({ progress }) => {
  const offset = 260 - (progress / 100) * 260;
  const tipY = 8 + (progress / 100) * 182;
  return (
    <div style={{ position:'fixed', right:16, top:'50%', transform:'translateY(-50%)', width:28, height:200, zIndex:3000, pointerEvents:'none' }}>
      <svg width="28" height="200" viewBox="0 0 28 200" style={{ animation:'tailGlow 3s ease infinite' }}>
        {/* track */}
        <path d="M14 8 Q22 32 14 62 Q6 92 14 122 Q22 152 14 178 Q10 188 14 195"
          stroke="rgba(178,34,34,0.13)" strokeWidth="3" fill="none" strokeLinecap="round"/>
        {/* filled */}
        <path d="M14 8 Q22 32 14 62 Q6 92 14 122 Q22 152 14 178 Q10 188 14 195"
          stroke={C.crimson} strokeWidth="3" fill="none" strokeLinecap="round"
          strokeDasharray="260" strokeDashoffset={offset}
          style={{ transition:'stroke-dashoffset .18s ease' }}/>
        {/* moving tip */}
        <circle cx="14" cy={tipY} r="5" fill={C.crimson} style={{ filter:'drop-shadow(0 0 5px rgba(178,34,34,.7))' }}/>
      </svg>
    </div>
  );
};

