            <h2 style={{ fontFamily:fa?"'Vazirmatn',sans-serif":"'Playfair Display',serif", fontSize:'clamp(26px,3.5vw,48px)', fontWeight:fa?700:400, color:C.ink, lineHeight:1.2, marginBottom:20 }}>
              {fa?'جایی که اشتیاق با مهارت پیوند می‌خورد':'Where Passion\nMeets Precision'}
            </h2>
