/* ─── MAIN APP ───────────────────────────────────────────────────────────── */
export default function CrimsonCatAtelier() {
  const [ready, setReady] = useState(false);
  const [lang, setLang] = useState('en');
  const [scrolled, setScrolled] = useState(false);
  const [progress, setProgress] = useState(0);

  useEffect(()=>{
    const h = ()=>{
      setScrolled(window.scrollY>70);
      const total = document.documentElement.scrollHeight - window.innerHeight;
      setProgress(total>0?(window.scrollY/total)*100:0);
    };
    window.addEventListener('scroll', h, {passive:true});
    return ()=>window.removeEventListener('scroll', h);
  },[]);

  return (
    <>
      <Fonts/>
      <GS/>
      {!ready && <Intro logoSrc={LOGO_SRC} onDone={()=>setReady(true)}/>}
      {ready && (
        <div style={{ minHeight:'100vh', background:C.paper, animation:'fadeIn .9s ease both' }}>
          <CursorSystem/>
          <InkSplats/>
          <TailIndicator progress={progress}/>
          <Header lang={lang} setLang={setLang} scrolled={scrolled} logoSrc={LOGO_SRC}/>
          <main>
            <Hero lang={lang} logoSrc={LOGO_SRC}/>
            <About lang={lang}/>
            <Classes lang={lang}/>
            <PaintingStyles lang={lang}/>
            <Gallery lang={lang}/>
            <Instructors lang={lang}/>
            <ArtQuiz lang={lang}/>
            <Testimonials lang={lang}/>
            <Newsletter lang={lang}/>
          </main>
          <Footer lang={lang} logoSrc={LOGO_SRC}/>
        </div>
      )}
    </>
  );
}
